{
  "name": "hello-colors-app",
  "version": "1.0.0",
  "description": "Express + Tailwind project (install server and build dependencies)",
  "main": "src/index.js",
  "scripts": {
    "start": "node src/index.js",
    "dev": "concurrently \"nodemon src/index.js\" \"tailwindcss -i ./src/styles.css -o ./public/styles.css --watch\"",
    "build:css": "tailwindcss -i ./src/styles.css -o ./public/styles.css --minify",
    "test": "node ./tests/test.js"
  },
  "keywords": [],
  "author": "",
  "license": "MIT",
  "dependencies": {
    "express": "^4.18.2"
  },
  "devDependencies": {
    "tailwindcss": "^3.4.6",
    "postcss": "^8.4.21",
    "autoprefixer": "^10.4.14",
    "nodemon": "^2.0.22",
    "concurrently": "^8.0.1"
  }
}

const fs = require('fs');
const assert = require('assert');

// Check package.json exists and has expected name
const pkgRaw = fs.readFileSync('package.json', 'utf8');
const pkg = JSON.parse(pkgRaw);
assert.strictEqual(pkg.name, 'hello-colors-app', 'package.json name should be hello-colors-app');

// Check dependencies exist in package.json
assert.ok(pkg.dependencies && typeof pkg.dependencies === 'object', 'package.json should have dependencies');
const deps = pkg.dependencies;
['express'].forEach(d => {
  assert.ok(deps[d], `dependency ${d} should be listed in package.json`);
});

// Check devDependencies
assert.ok(pkg.devDependencies && typeof pkg.devDependencies === 'object', 'package.json should have devDependencies');
const devs = pkg.devDependencies;
['tailwindcss','postcss','autoprefixer','nodemon','concurrently'].forEach(d => {
  assert.ok(devs[d], `devDependency ${d} should be listed in package.json`);
});

// Check scripts
assert.ok(pkg.scripts && pkg.scripts.start, 'start script should exist');
assert.ok(pkg.scripts.dev, 'dev script should exist');
assert.ok(pkg.scripts['build:css'], 'build:css script should exist');
assert.ok(pkg.scripts.test, 'test script should exist');

// Check config files exist
assert.ok(fs.existsSync('tailwind.config.js'), 'tailwind.config.js should exist');
assert.ok(fs.existsSync('postcss.config.js'), 'postcss.config.js should exist');

// Check src files
assert.ok(fs.existsSync('src/index.js'), 'src/index.js should exist');
const serverSrc = fs.readFileSync('src/index.js', 'utf8');
assert.ok(serverSrc.includes("express"), 'src/index.js should reference express');

// Check styles and public assets
assert.ok(fs.existsSync('src/styles.css'), 'src/styles.css should exist');
const styles = fs.readFileSync('src/styles.css', 'utf8');
assert.ok(styles.includes('@tailwind base'), 'src/styles.css should include Tailwind directives');

assert.ok(fs.existsSync('public/index.html'), 'public/index.html should exist');
const indexHtml = fs.readFileSync('public/index.html', 'utf8');
assert.ok(indexHtml.includes('Hello Colors App'), 'public/index.html should mention project name');

console.log('All checks passed.');

const express = require('express');
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3000;

// Serve static files from public
app.use(express.static(path.join(__dirname, '..', 'public')));

// Simple API endpoint (future use)
app.get('/api/hello', (req, res) => {
  res.json({ message: 'Hello World' });
});

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

@tailwind base;
@tailwind components;
@tailwind utilities;

